import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Header = ({ onLogout, user: propUser }) => {
  const navigate = useNavigate();
  const [user, setUser] = useState(propUser || { name: 'Administrator' });

  useEffect(() => {
    if (!propUser) {
      const fetchUser = async () => {
        try {
          const response = await axios.get('/auth/me', { withCredentials: true });
          if (response.data.success) {
            setUser(response.data.user);
          }
        } catch (error) {
          console.error('Failed to fetch user:', error);
        }
      };
      fetchUser();
    }
  }, [propUser]);

  const currentDate = new Date().toLocaleDateString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });

  const handleLogout = async () => {
    try {
      await axios.post('/auth/logout', {}, { withCredentials: true });
      localStorage.removeItem('remembered_username');
      if (onLogout) onLogout();
      navigate('/login');
    } catch (error) {
      console.error('Logout failed:', error);
    }
  };

  return (
    <header className="header">
      <div>
        <div className="header-title">Welcome back, {user.name || 'Administrator'}!</div>
        <div className="header-date">{currentDate}</div>
      </div>
      <div className="header-right">
        <div className="user-info" onClick={handleLogout}>
          <div className="user-avatar">
            {user.name?.charAt(0)?.toUpperCase() || 'A'}
          </div>
          <span>Logout</span>
        </div>
      </div>
    </header>
  );
};

export default Header;
